 10→import './search_dropdown.scss';
 11→
 12→export interface SearchDropdownOption {
 13→  label: string;
 14→  value: string;
 15→  icon?: ReactNode;
 16→}
 17→
 18→export interface SearchDropdownSection {
 19→  title?: string;
 20→  options: SearchDropdownOption[];
 21→}
 22→
 23→interface SearchDropdownProps {
 24→  sections: SearchDropdownSection[];
 25→  value: string;
 26→  onChange: (value: string) => void;
 27→  placeholder?: string;
 28→}
 29→
 30→export function SearchDropdown({
 31→  sections,
 32→  value,
 33→  onChange,
 34→  placeholder = 'All',
 35→}: SearchDropdownProps) {
 36→  const [open, setOpen] = useState(false);
 37→  const [activeIndex, setActiveIndex] = useState(0);
 38→  const triggerRef = useRef<HTMLButtonElement>(null);
 39→  const dropdownRef = useRef<HTMLDivElement>(null);
 40→  const idPrefix = useId();
 41→
 42→  const nonEmptySections = useMemo(
 43→    () => sections.filter(s => s.options.length > 0),
 44→    [sections],
 45→  );
 46→
 47→  const flatOptions = useMemo(
 48→    () => nonEmptySections.flatMap(s => s.options),
 49→    [nonEmptySections],
 50→  );
 51→
 52→  const sectionOffsets = useMemo(() => {
 53→    const offsets: number[] = [];
 54→    let total = 0;
 55→    for (const section of nonEmptySections) {
 56→      offsets.push(total);
 57→      total += section.options.length;
 58→    }
 59→    return offsets;
 60→  }, [nonEmptySections]);
 61→
 62→  const selectedOption = flatOptions.find(o => o.value === value);
 63→  const selectedLabel = selectedOption?.label ?? placeholder;
 64→
 65→  const toggle = useCallback(() => {
 66→    setOpen(prev => !prev);
 67→  }, []);
 68→
 69→  useEffect(() => {
 70→    if (!open) return;
 71→    const currentIdx = flatOptions.findIndex(o => o.value === value);
 72→    setActiveIndex(currentIdx >= 0 ? currentIdx : 0);
 73→    dropdownRef.current?.focus();
 74→  }, [
 75→    open,
 76→    flatOptions,
 77→    value,
 78→  ]);
 79→
 80→  const selectOption = useCallback(
 81→    (index: number) => {
 82→      const option = flatOptions[index];
 83→      if (!option) return;
 84→      onChange(option.value);
 85→      setOpen(false);
 86→      triggerRef.current?.focus();
 87→    },
 88→    [
 89→      flatOptions,
 90→      onChange,
 91→    ],
 92→  );
 93→
 94→  useEffect(() => {
 95→    if (!open) return;
 96→
 97→    function handleKeyDown(e: KeyboardEvent) {
 98→      if (e.key === 'Escape' || e.key === 'Tab') {
 99→        e.preventDefault();
100→        e.stopPropagation();
101→        setOpen(false);
102→        triggerRef.current?.focus();
103→        return;
104→      }
105→
106→      if (e.key === 'ArrowDown') {
107→        e.preventDefault();
108→        e.stopPropagation();
109→        setActiveIndex(i => (i < flatOptions.length - 1 ? i + 1 : 0));
110→        return;
111→      }
112→
113→      if (e.key === 'ArrowUp') {
114→        e.preventDefault();
115→        e.stopPropagation();
116→        setActiveIndex(i => (i > 0 ? i - 1 : flatOptions.length - 1));
117→        return;
118→      }
119→
120→      if (e.key === 'Enter') {
121→        e.preventDefault();
122→        e.stopPropagation();
123→        selectOption(activeIndex);
124→      }
125→    }
126→
127→    window.addEventListener('keydown', handleKeyDown, true);
128→    return () => window.removeEventListener('keydown', handleKeyDown, true);
129→  }, [
130→    open,
131→    activeIndex,
132→    flatOptions,
133→    selectOption,
134→  ]);
135→
136→  useEffect(() => {
137→    if (!open) return;
138→
139→    function handleClickOutside(e: MouseEvent) {
140→      const target = e.target as Node;
141→      if (
142→        dropdownRef.current &&
143→        !dropdownRef.current.contains(target) &&
144→        triggerRef.current &&
145→        !triggerRef.current.contains(target)
146→      ) {
147→        setOpen(false);
148→      }
149→    }
150→
151→    document.addEventListener('mousedown', handleClickOutside);
152→    return () => document.removeEventListener('mousedown', handleClickOutside);
153→  }, [open]);
154→
155→  useEffect(() => {
156→    if (!open || !dropdownRef.current) return;
157→    const el = dropdownRef.current.querySelector<HTMLElement>(
158→      `[data-search-dropdown-index="${activeIndex}"]`,
159→    );
160→    el?.scrollIntoView({ block: 'nearest' });
161→  }, [
162→    open,
163→    activeIndex,
164→  ]);
165→
166→  if (flatOptions.length === 0) return null;
167→
168→  return (
169→    <div className="search-dropdown">
170→      <button
171→        ref={triggerRef}
172→        className="search-dropdown__trigger"
173→        type="button"
174→        onClick={toggle}
175→        aria-haspopup="listbox"
176→        aria-expanded={open}
177→        aria-label="Filter by type"
178→      >
179→        <span className="search-dropdown__trigger-label">{selectedLabel}</span>
180→        <svg
181→          className={`search-dropdown__trigger-chevron${open ? ' search-dropdown__trigger-chevron--open' : ''}`}
182→          width="10"
183→          height="10"
184→          viewBox="0 0 10 10"
185→          fill="none"
186→        >
187→          <path
188→            d="M2.5 3.75L5 6.25L7.5 3.75"
189→            stroke="currentColor"
190→            strokeWidth="1.2"
191→            strokeLinecap="round"
192→            strokeLinejoin="round"
193→          />
194→        </svg>
195→      </button>
196→      {open && (
197→        <div
198→          ref={dropdownRef}
199→          className="search-dropdown__menu"
200→          role="listbox"
201→          aria-activedescendant={`${idPrefix}-option-${activeIndex}`}
202→          aria-label="Filter options"
203→          tabIndex={-1}
204→        >
205→          <div className="search-dropdown__menu-content">
206→            {nonEmptySections.map((section, sectionIndex) => {
207→              const offset = sectionOffsets[sectionIndex] ?? 0;
208→              const titleId = section.title
209→                ? `${idPrefix}-section-${sectionIndex}`
210→                : undefined;
211→
212→              return (
213→                <div key={sectionIndex}>
214→                  {sectionIndex > 0 && (
215→                    <div
216→                      className="search-dropdown__separator"
217→                      role="separator"
218→                    />
219→                  )}
220→                  <div role="group" aria-labelledby={titleId}>
221→                    {titleId && (
222→                      <div
223→                        id={titleId}
224→                        className="search-dropdown__section-title"
225→                        role="presentation"
226→                      >
227→                        {section.title}
228→                      </div>
229→                    )}
230→                    {section.options.map((option, optionIndex) => {
231→                      const idx = offset + optionIndex;
232→                      const isActive = idx === activeIndex;
233→                      const isSelected = option.value === value;
234→                      return (
235→                        <div
236→                          key={option.value}
237→                          id={`${idPrefix}-option-${idx}`}
238→                          className={`search-dropdown__option${isActive ? ' search-dropdown__option--active' : ''}`}
239→                          data-search-dropdown-index={idx}
240→                          role="option"
241→                          aria-selected={isSelected}
242→                          onClick={() => selectOption(idx)}
243→                          onMouseEnter={() => setActiveIndex(idx)}
244→                        >
245→                          {option.icon && (
246→                            <span className="search-dropdown__option-icon">
247→                              {option.icon}
248→                            </span>
249→                          )}
250→                          <span className="search-dropdown__option-label">
251→                            {option.label}
252→                          </span>
253→                          {isSelected && (
254→                            <svg
255→                              className="search-dropdown__check"
256→                              width="12"
257→                              height="12"
258→                              viewBox="0 0 12 12"
259→                              fill="none"
260→                            >
261→                              <path
262→                                d="M2.5 6L5 8.5L9.5 3.5"
263→                                stroke="currentColor"
264→                                strokeWidth="1.5"
265→                                strokeLinecap="round"
266→                                strokeLinejoin="round"
267→                              />
268→                            </svg>
269→                          )}
270→                        </div>
271→                      );
272→                    })}
273→                  </div>
274→                </div>
275→              );
276→            })}
277→          </div>
278→        </div>
279→      )}
280→    </div>
281→  );
282→}
